#include <stdio.h>
int main() {
    int T, k, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %lld", &k, &N);
        long long A[k], C[k];
        for (int i = 0; i < k; i++) {
            scanf("%lld", &A[i]);
        }
        for (int i = 0; i < k; i++) {
            scanf("%lld", &C[i]);
        }
        for (int i = k; i < N; i++) {
            long long sum = 0;
            for (int j = 0; j < k; j++) {
                sum = (sum + A[(i-1-j)%k] * C[j]) % 104857601;
            }
            A[i%k] = sum;
        }
        printf("%lld\n", A[(N-1)%k]);
    }
    return 0;
}

