code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int k = sc.nextInt();
            long N = sc.nextLong();
            long[] A = new long[k];
            long[] C = new long[k];
            for (int i = 0; i < k; i++) {
                A[i] = sc.nextLong();
            }
            for (int i = 0; i < k; i++) {
                C[i] = sc.nextLong();
            }
            for (int i = k; i < N; i++) {
                long sum = 0;
                for (int j = 0; j < k; j++) {
                    sum = (sum + A[(i-1-j)%k] * C[j]) % 104857601;
                }
                A[i%k] = sum;
            }
            System.out.println(A[(N-1)%k]);
        }
    }
}

